import React, { useEffect, useState } from "react";
import axios from "axios";

export default function MealPlan() {
  const [plans, setPlans] = useState([]);

  useEffect(() => {
    axios
      .get("http://localhost:5000/api/dietplan/my-plans", {
        headers: {
          Authorization: "Bearer " + localStorage.getItem("token")
        }
      })
      .then(res => setPlans(res.data))
      .catch(err => console.log(err));
  }, []);

  if (plans.length === 0) {
    return <h3 className="m-5 text-center">No Meal Plans Yet...</h3>;
  }

  return (
    <div className="container my-4">
      <h2>Your AI Meal Plan</h2>
      {plans.map((plan, i) => (
        <div key={i} className="card my-3 p-3">
          <h4>{plan.patientName} - {plan.disease}</h4>
          {plan.meals.map((m, idx) => (
            <div key={idx}>
              <h5>{m.time}</h5>
              <ul>
                {m.items.map((f, j) => <li key={j}>{f}</li>)}
              </ul>
            </div>
          ))}
        </div>
      ))}
    </div>
  );
}
